let THREE: any = null;
let OrbitControls: any = null;
let threeRuntimeLoadPromise: Promise<void> | null = null;

const ensureThreeRuntimeLoaded = async () => {
  if (THREE && OrbitControls) {
    return;
  }

  if (!threeRuntimeLoadPromise) {
    threeRuntimeLoadPromise = (async () => {
      const threeModule: any = await import("three");
      let controlsModule: any = null;
      try {
        controlsModule = await import(
          "three/examples/jsm/controls/OrbitControls.js"
        );
      } catch {
        controlsModule = await import("three/addons/controls/OrbitControls.js");
      }

      const threeNs =
        (threeModule as any)?.WebGLRenderer != null
          ? threeModule
          : (threeModule as any)?.default ?? null;
      const controlsCtor =
        (controlsModule as any)?.OrbitControls ??
        (controlsModule as any)?.default?.OrbitControls ??
        (controlsModule as any)?.default ??
        null;

      if (!threeNs?.WebGLRenderer || !controlsCtor) {
        throw new Error("Failed to load Three.js runtime");
      }

      THREE = threeNs;
      OrbitControls = controlsCtor;
    })().catch((error) => {
      threeRuntimeLoadPromise = null;
      throw error;
    });
  }

  await threeRuntimeLoadPromise;
};

