  const chunkDistribution = useMemo(() => {
    if (!candles.length) return [];
    const bars = Math.max(1, chunkBars);
    const sums = new Array(bars).fill(0);
    let count = 0;
    for (let endIndex = bars - 1; endIndex < candles.length; endIndex++) {
      const startIdx = endIndex - (bars - 1);
      const startClose = candles[startIdx]?.close;
      if (typeof startClose !== "number" || startClose === 0) continue;
      let valid = true;
      for (let j = 0; j < bars; j++) {
        const c = candles[startIdx + j];
        if (!c || typeof c.close !== "number") {
          valid = false;
          break;
        }
      }
      if (!valid) continue;
      for (let j = 0; j < bars; j++) {
        const price = candles[startIdx + j].close;
        sums[j] += (price - startClose) / startClose;
      }
      count++;
    }
    if (count === 0) return [];
    return sums.map((sum, idx) => ({ x: idx + 1, y: sum / count }));
  }, [candles, chunkBars]);
  const chunkMedianDistribution = useMemo(() => {
    if (!candles.length) return [];
    const bars = Math.max(1, chunkBars);
    const changes = Array.from({ length: bars }, () => []);
    for (let endIndex = bars - 1; endIndex < candles.length; endIndex++) {
      const startIdx = endIndex - (bars - 1);
      const startClose = candles[startIdx]?.close;
      if (typeof startClose !== "number" || startClose === 0) continue;
      let valid = true;
      for (let j = 0; j < bars; j++) {
        const c = candles[startIdx + j];
        if (!c || typeof c.close !== "number") {
          valid = false;
          break;
        }
      }
      if (!valid) continue;
      for (let j = 0; j < bars; j++) {
        const price = candles[startIdx + j].close;
        changes[j].push((price - startClose) / startClose);
      }
    }
    return changes.map((arr, idx) => {
      if (!arr.length) return { x: idx + 1, median: 0 };
      const sorted = arr.slice().sort((a, b) => a - b);
      const mid = Math.floor(sorted.length / 2);
      const median =
        sorted.length % 2 === 1
          ? sorted[mid]
          : (sorted[mid - 1] + sorted[mid]) / 2;
      return { x: idx + 1, median };
    });
  }, [candles, chunkBars]);
