                            title="Sort by minimum value"
                          >
                            <span>Min</span>
                            {dimSortCol === "min" ? (
                              <span style={{ opacity: 0.75 }}>
                                {dimSortDir === 1 ? "▲" : "▼"}
                              </span>
                            ) : null}
